      write_word(ADDR_KEY0 + 5, 32'h0);
      write_word(ADDR_KEY0 + 6, 32'h0);
      write_word(ADDR_KEY0 + 7, 32'h0);
    end
  endtask

  task write_block(input [127:0] b);
    begin
      write_word(ADDR_BLOCK0 + 0, b[127:96]);
      write_word(ADDR_BLOCK0 + 1, b[95:64]);
      write_word(ADDR_BLOCK0 + 2, b[63:32]);
      write_word(ADDR_BLOCK0 + 3, b[31:0]);
    end
  endtask

  task read_result(output [127:0] r);
    reg [31:0] w0,w1,w2,w3;
    begin
      read_word(ADDR_RESULT0 + 0, w0);
      read_word(ADDR_RESULT0 + 1, w1);
      read_word(ADDR_RESULT0 + 2, w2);
      read_word(ADDR_RESULT0 + 3, w3);
      r = {w0,w1,w2,w3};
    end
  endtask

  task do_init128;
    begin
      write_word(ADDR_CTRL, 32'h00000001);
      wait_ready();
    end
  endtask

  task do_encrypt128(input [127:0] b, output [127:0] r);
    begin
      write_block(b);
      write_word(ADDR_CTRL, 32'h00000006); // next=1, encdec=1, keylen=0
      wait_valid();
      read_result(r);
    end
  endtask

