    pt_trig1 = {64'hA5A5_A5A5_A5A5_A5A5, 64'h0123_4567_89AB_CDEF};
    pt_trig2 = {64'h5A5A_5A5A_5A5A_5A5A, 64'hFEDC_BA98_7654_3210};

